// Script Continued Below
var Out_of_Office = Class.create();
// this is used in the Banner also
Out_of_Office.CONST_TASK_OUT_OF_OFFICE_SUSPENSE_EMPTY_FILTER = "^ooo_u_end_date>=javascript:gs.beginningOfToday()^task_suspense_dateISEMPTY";
Out_of_Office.CONST_TASK_OUT_OF_OFFICE_SUSPENSE_NOT_EMPTY_FILTER = "^task_suspense_dateISNOTEMPTY^ooo_u_start_dateMORETHANtask_suspense_date@hour@before@0^ooo_u_end_date>=javascript:gs.beginningOfToday()";

Out_of_Office.CONST_VIEW_NAME_TASK_OUT_OF_OFFICE = "x_153465_discovert_task_users_ooo";
Out_of_Office.CONST_TABLE_NAME_OUT_OF_OFFICE = "x_153465_discovert_out_of_office";
Out_of_Office.prototype = {
    initialize: function() {
		this.tableRouteTaskInstance = 'x_153465_discovert_route_task_instance';
	},

	// STRY0130635 - this is used to set the default out of office object
	_initTaskOOO: function(){
		var task_ooo = {
			user_id: "",
			userDisplayValue: "",
			ooo_schedule: []
		};
		return task_ooo;
	},

	// STRY0134743 - creates the warning message HTML for the Request Out of office. Done in script include and called from business rule onload so it can be used in portal and platform
	getRequestOutOfOfficeWarningHTML: function(){
		var warningMessage = gs.getMessage("Tasker - Warning: Some member(s) who can provide a response are out of office and may be unable to respond.");
		var href_click_here = '<a>' +
				gs.getMessage("Tasker - click here") +
				'</a>';
		var moreInfoMessage = gs.getMessage("Tasker - Please {0} for more information.",[href_click_here]);
		var requestOOOMessage = 
			warningMessage + 
			moreInfoMessage;
		requestOOOMessage = requestOOOMessage.replace(/'/g, "&apos;");
		requestOOOMessage = requestOOOMessage.replace(/"/g, "&quot;");
				var requestOOOMessageHTML = 
					'<span class="dtech-ooo-background-color">' +
							'<span>' +
								'<img src="OOO16.svg" class="dtech-ooo-pad-right-10"/>' +
							'</span>' +
							'<span class="dtech-ooo-message-text">' +
									requestOOOMessage +
							'</span>' +
					'</span>';

/*
		var requestOOOMessageHTML = 
				'<table class="dtech-ooo-background-color">' +
					'<tr>' +
						'<td>' +
							'<span>' +
								'<img src="OOO16.svg" class="dtech-ooo-pad-right-10"/>' +
							'</span>' +
						'</td>' +
						'<td>' +
							'<span class="dtech-ooo-message-text">' +
									requestOOOMessage +
							'</span>' +
						'</td>' +
					'</tr>' +
				'</table>';
*/
		return requestOOOMessageHTML;
	},


	// STRY0134743 - load Task responders and see if any are out of the office
	requestResponderIsOutOfOffice: function (task_id){
		var isRequestResponderIsOutOfOffice = false;
		var responderList = this._getRespondersList(task_id);
		if(responderList  != ""){
			isRequestResponderIsOutOfOffice = this._isAnyUserOutOfOffice(responderList);
		}
		// STRY0134743 - load all of the task users and see if any are out of the office
		return isRequestResponderIsOutOfOffice;
	},

	getRequestUsersOOO: function (task_id){
		var usersLoaded = "";
		var ooo_users = {};
		var o_user_ooo;
		var o_user_ooo_schedule = {};

		var responderList = this._getRespondersList(task_id);
		var gr_ooo = new GlideRecordSecure(Out_of_Office.CONST_TABLE_NAME_OUT_OF_OFFICE);
		var encodedFilter = "u_userIN" + responderList + "^u_start_date<=javascript:gs.beginningOfToday()^u_end_date>=javascript:gs.endOfToday()";
		gr_ooo.addEncodedQuery(encodedFilter);
		gr_ooo.query();
		while(gr_ooo.next()){
			var user_id  = gr_ooo.getValue("u_user");
			// is user loaded yet
			if(usersLoaded.indexOf(user_id) == -1) {
				if(usersLoaded != ""){
					usersLoaded = usersLoaded + ","; 
				}
				usersLoaded += user_id;
				// load user
				o_user_ooo = this._initTaskOOO();
				o_user_ooo.user_id = gr_ooo.getValue("u_user");
				o_user_ooo.userDisplayValue = gr_ooo.getDisplayValue("u_user");
				// add this user to the task ooo object
				ooo_users[user_id]=o_user_ooo;
			}
			// add schedules for the user
			o_user_ooo_schedule = {};
			o_user_ooo_schedule.user_id = gr_ooo.getValue("u_user");
			o_user_ooo_schedule.userDisplayValue = gr_ooo.getDisplayValue("u_user");
			o_user_ooo_schedule.start_date = gr_ooo.getValue("u_start_date");
			o_user_ooo_schedule.end_date = gr_ooo.getValue("u_end_date");
			o_user_ooo_schedule.message = gr_ooo.getDisplayValue("u_out_of_office_message");
			o_user_ooo.ooo_schedule.push(o_user_ooo_schedule);
		}
		return ooo_users;
	},


	// STRY0134743 - load Task responders and see if any are out of the office
	_getRespondersList: function(task_id){
		var responder_list = "";
		if(task_id && task_id != ""){
			var gr_task = new GlideRecordSecure(this.tableRouteTaskInstance);
			if(gr_task.get(task_id)){
				// get users
				var task_owner_id = gr_task.getValue("u_task_requester");
				if(task_owner_id && task_owner_id != ""){
					responder_list = task_owner_id;
				}

				var primary_assignee = gr_task.getValue("primary_assignee");
				if(primary_assignee && primary_assignee != ""){
					var gr_ou = new GlideRecordSecure("x_153465_discovert_discover_office_hierarchy");
					if(gr_ou.get(primary_assignee)){
						var task_managers = gr_ou.getValue("tasking_authorities");
						if(task_managers && task_managers != ''){
							if(responder_list != ""){
								responder_list += ",";
							}
							responder_list += task_managers;
						}
						var tasking_authorities = gr_ou.getValue("u_global_authorities");
						if(tasking_authorities && tasking_authorities != ''){
							if(responder_list != ""){
								responder_list += ",";
							}
							responder_list += tasking_authorities;
						}						
					}
				}
			}
		}
		return responder_list;		
	},

	// STRY0134743 - are any of the users in the list currently out of office
	//               NOTE: this is used for  a single user also
	_isAnyUserOutOfOffice: function(listOfUsers){
		var oneOrMoreUsersOutOfOffice = false;
		var ga_ooo = new GlideAggregate(Out_of_Office.CONST_TABLE_NAME_OUT_OF_OFFICE);
		var encodedQuery = "u_userIN" + listOfUsers + "^u_start_date<=javascript:gs.beginningOfToday()^u_end_date>=javascript:gs.endOfToday()";
		ga_ooo.addEncodedQuery(encodedQuery);
		ga_ooo.addAggregate('COUNT', "u_user");
		ga_ooo.query();
		if(ga_ooo.next()){
			var oooCount = ga_ooo.getAggregate('COUNT', "u_user");
			if(oooCount>0){
				oneOrMoreUsersOutOfOffice = true;
			}
		}
		return oneOrMoreUsersOutOfOffice;
	},

	// STRY0130635 - get the list of scheduled out of office for the user during task period
	isUserOutOfOfficeSuspenseDate: function (suspenseDateDisplayValue, user_id){
		var suspenseDateNextDayValue;
		var gdtSuspense;
		var a_schedule = [];
		var gr_ooo = new GlideRecordSecure(Out_of_Office.CONST_TABLE_NAME_OUT_OF_OFFICE);
		var task_ooo = this._initTaskOOO();
		task_ooo.user_id = user_id;
		gr_ooo.addQuery("u_user", user_id);
		if(suspenseDateDisplayValue && suspenseDateDisplayValue != ''){
			// DFCT0011588 - when suspense date was empty the lines to set gdtSuspense failed, moved them inside of the if statement
			gdtSuspense = new GlideDateTime(suspenseDateDisplayValue);
			gdtSuspense.addDaysLocalTime(1);
			suspenseDateNextDayValue = gdtSuspense.getDate();
			gr_ooo.addQuery("u_start_date", "<=", suspenseDateNextDayValue);
		}
		gr_ooo.addQuery("u_end_date", ">=", gs.daysAgoStart(0));
		gr_ooo.query();
		while(gr_ooo.next()){
			var o_user_ooo = {};
			var numStrStartDate = gr_ooo.getValue("u_start_date");
			var numEndDate = gr_ooo.getValue("u_end_date");
			var gd_start = new GlideDateTime(numStrStartDate);
			var gd_end = new GlideDateTime(numEndDate);
			o_user_ooo.userDisplayValue = gr_ooo.getDisplayValue("u_user");
			o_user_ooo.user_id = user_id;
			o_user_ooo.start_date = gd_start.getDate().getByFormat('MMM dd');
			o_user_ooo.end_date = gd_end.getDate().getByFormat('MMM dd');
			o_user_ooo.message = gr_ooo.getDisplayValue("u_out_of_office_message");
			a_schedule.push(o_user_ooo);
		}
		task_ooo.ooo_schedule = a_schedule;
		return task_ooo;
	},

	// DFCT0011483 - needed to set related list fitlers in a special way
	getUserScheduleRelatedListFilter: function (user_id){
		var fitler;
		fitler = "u_user=" + user_id + "^u_end_date>=javascript:gs.endOfToday()";
		return fitler;
	},

	// DFCT0011483 - needed to set related list fitlers in a special way
	getUserHistoryRelatedListFilter: function (user_id){
		var fitler;
		fitler = "u_user=" + user_id + "^u_end_date<javascript:gs.endOfToday()";
		return fitler;
	},

	_getTaskAllUserFilter: function(task_id){
		var task_filter = "task_sys_id=" + task_id;
		var filter;
		filter = task_filter + Out_of_Office.CONST_TASK_OUT_OF_OFFICE_SUSPENSE_EMPTY_FILTER;
		filter = filter + "^NQ" + task_filter + Out_of_Office.CONST_TASK_OUT_OF_OFFICE_SUSPENSE_NOT_EMPTY_FILTER;		
		filter = filter + "^ORDERBYooo_u_user";

		return filter;
	},

	getActiveTaskOOOSchedules: function(task_id){
		var usersLoaded = "";
		var task_ooo = {};
		var o_task_user_ooo;
		var o_user_ooo = {};

		var gr_task_ooo = new GlideRecordSecure(Out_of_Office.CONST_VIEW_NAME_TASK_OUT_OF_OFFICE);
		var encodedFilter = this._getTaskAllUserFilter(task_id);
		gr_task_ooo.addEncodedQuery(encodedFilter);
		gr_task_ooo.query();
		while(gr_task_ooo.next()){
			var user_id  = gr_task_ooo.getValue("ooo_u_user");
			// is user loaded yet
			if(usersLoaded.indexOf(user_id) == -1) {
				if(usersLoaded != ""){
					usersLoaded = usersLoaded + ","; 
				}
				usersLoaded += user_id;
				// load user
				o_task_user_ooo = this._initTaskOOO();
				o_task_user_ooo.user_id = gr_task_ooo.getValue("ooo_u_user");
				o_task_user_ooo.userDisplayValue = gr_task_ooo.getDisplayValue("ooo_u_user");
				// add this user to the task ooo object
				task_ooo[user_id]=o_task_user_ooo;
			}
			// add schedules for the user
			o_user_ooo = {};
			o_user_ooo.user_id = gr_task_ooo.getValue("ooo_u_user");
			o_user_ooo.userDisplayValue = gr_task_ooo.getDisplayValue("ooo_u_user");
			o_user_ooo.start_date = gr_task_ooo.getValue("ooo_u_start_date");
			o_user_ooo.end_date = gr_task_ooo.getValue("ooo_u_end_date");
			o_user_ooo.message = gr_task_ooo.getDisplayValue("ooo_u_out_of_office_message");
			o_task_user_ooo.ooo_schedule.push(o_user_ooo);
		}
		return task_ooo;
	},

	// STRY0130998
	_getDescendantTasksAllUserFilter: function(task_id){		
		var task_filter = 'task_sys_id=' + task_id + '^ORtask_u_all_ancestors_tasksLIKE' + task_id;
		var filter;
		filter = task_filter + Out_of_Office.CONST_TASK_OUT_OF_OFFICE_SUSPENSE_EMPTY_FILTER;
		filter = filter + "^NQ" + task_filter + Out_of_Office.CONST_TASK_OUT_OF_OFFICE_SUSPENSE_NOT_EMPTY_FILTER;		
		filter = filter + "^ORDERBYooo_u_user";

		return filter;
	},

	// STRY0130998 
	getDescendantTasksIdOOOFilter: function (task_id){
		var task_id_filter = "none";
		var task_ids = "";

		var gr_descend_task_ooo = new GlideRecordSecure(Out_of_Office.CONST_VIEW_NAME_TASK_OUT_OF_OFFICE);
		var encodedFilter = this._getDescendantTasksAllUserFilter(task_id);
		gr_descend_task_ooo.addEncodedQuery(encodedFilter);
		gr_descend_task_ooo.query();
		while(gr_descend_task_ooo.next()){
			var current_task_id = gr_descend_task_ooo.task_sys_id;
			if(!task_ids.includes(current_task_id)){
				if(task_ids != ""){
					task_ids += ",";
				}
				task_ids += current_task_id;
			}
		}
		if(task_ids!=""){
			task_id_filter = "sys_idIN" + task_ids;
		}
		return task_id_filter;

	},

	// STRY0130998 
	// this is used by the publish call and can be used to determine if any descendents of a task has an OOO conflict
	hasDescendantTasksUserOOO: function(task_id){
		var bHasDescendantTasksUserOOO = false;

		var gr_descend_task_ooo = new GlideRecordSecure(Out_of_Office.CONST_VIEW_NAME_TASK_OUT_OF_OFFICE);
		var encodedFilter = this._getDescendantTasksAllUserFilter(task_id);
		gr_descend_task_ooo.addEncodedQuery(encodedFilter);
		gr_descend_task_ooo.query();
		if(gr_descend_task_ooo.next()){
			bHasDescendantTasksUserOOO = true;
		}
		return bHasDescendantTasksUserOOO;
	},

	// STRY0131003 - Task Tree- get all OOO schedules for all tasks in the task tree, Task Tree- OOO Visual Indicators
	// NOTE: test script for background execution run below this function
	getTaskTreeOOOSchedules: function(tree_id){
		var taskTreeOOO = [];
		var taskOOO;
		var userOOO;
		var task_id = "";
		var user_id = "";
		var gaTreeOOO = new GlideAggregate(Out_of_Office.CONST_VIEW_NAME_TASK_OUT_OF_OFFICE);
		gaTreeOOO.addQuery("task_u_task_tree", tree_id);
		gaTreeOOO.addAggregate('COUNT', "task_sys_id");
		gaTreeOOO.query();
		while (gaTreeOOO.next()){
			// reset the task object
			task_id = gaTreeOOO.getValue("task_sys_id");
			taskOOO = {};
			taskOOO.task_id = task_id;
			taskOOO.users = [];

			var gaTaskOOO = new GlideAggregate(Out_of_Office.CONST_VIEW_NAME_TASK_OUT_OF_OFFICE);
			var encodedQuery = this._getTaskAllUserFilter(task_id);
			gaTaskOOO.addEncodedQuery(encodedQuery);
			gaTaskOOO.addAggregate('COUNT', "ooo_u_user");
			gaTaskOOO.query();
			while (gaTaskOOO.next()){
				var oooCount = gaTaskOOO.getAggregate('COUNT', "ooo_u_user");
				if(oooCount>0){
					user_id = gaTaskOOO.getValue("ooo_u_user");
					// reset the task object
					userOOO = {};
					userOOO.user_id = user_id;
					userOOO.count = oooCount;
					taskOOO.users.push(userOOO);
				}
			}
			taskTreeOOO.push(taskOOO);

		}
		return taskTreeOOO;
	},
	/* -------------------------------------------------------
	//  PASTE INTO BACKGROUND EXECUTION TO TEST TREE OOO
	// -------------------------------------------------------
		var gr_taskTrees = new GlideRecord("x_153465_discovert_task_tree");
		gr_taskTrees.query();
		var maxTreeOOO;
		var maxTreeDisplayValue;
		var overallStart = new GlideDateTime().getNumericValue();
		var i = 0;
		var maxMS = 0;
		while(gr_taskTrees.next()){
			i++;
			var startTime = new GlideDateTime().getNumericValue();
			var treeOOOSchedule = new x_153465_discovert.Out_of_Office().getTaskTreeOOOSchedules(gr_taskTrees.getUniqueValue());
			var endTime = new GlideDateTime().getNumericValue();

			var msTaken = endTime - startTime;
			if(msTaken > maxMS){
				maxMS = msTaken;
				maxTreeOOO = treeOOOSchedule;
				maxTreeDisplayValue= gr_taskTrees.getDisplayValue();
			}

			//   gs.info ("RJ - testing - Task Tree: " + gr_taskTrees.getDisplayValue() + " - number of miliseconds: " + msTaken);
			//    gs.info ("RJ - testing - Task Tree: " + gr_taskTrees.getDisplayValue() + " treeOOOSchedule: " + JSON.stringify(treeOOOSchedule));
		}

		var overallEnd = new GlideDateTime().getNumericValue();

		var overallMS = overallEnd - overallStart;
		var averageMS = overallMS / i;

		gs.info ("RJ - testing - total task trees processed: " + i + " - total time: " + overallMS + " - Max Time: " + maxMS + " - average time: " + averageMS);
		gs.info ("RJ - testing - Max Task Tree: " + maxTreeDisplayValue + " treeOOOSchedule: " + JSON.stringify(maxTreeOOO));
	 -------------------------------------------------------
	 // END BACKGROUND SCRIPT
	  ------------------------------------------------------- */
	// STRY0130628 - Out of Office Modal- Success and Warning Toast
	getUserOOOTaskConflictCount: function(user_id){
		// retrn the count using the filter used by banner
		var count = 0;
		var hasConflict = false;
		var ga_count = new GlideAggregate(this.tableRouteTaskInstance);
		var filter = this.getUserOOOTaskConflictFilter(user_id);
		ga_count.addEncodedQuery(filter);
		ga_count.addAggregate('COUNT');
		ga_count.query();
		if (ga_count.next()) {

			count = ga_count.getAggregate('COUNT');
		}
		if(count > 0){
			hasConflict = true;
		}
		return hasConflict;
	},

	// get the URL for the success info message link to open taask conflict page for the users
	getUserOOOTaskConflictURL: function(user_id){
		var filter = this.getUserOOOTaskConflictFilter(user_id);

		var href = '?id=discovertasker_detailsdrilldown&view=sp&table=' + this.tableRouteTaskInstance + 
			'&filter=' + filter + '&o=suspense_date&d=asc&label=' + gs.getMessage("Tasker - My Conflicting Schedules (Out of Office)");

		var userTaskConflict_link = "<span style='font-family: georgia, palatino; font-size: 12pt;'><a href='" + href + "'>" + 
			gs.getMessage("Tasker - Take me to my Tasks...") +
			"</a></span>";

		return userTaskConflict_link;
	},

	// STRY0130630 - Banner Notification & Task List- My Conflicting Schedules (Out of Office)
	getUserOOOTaskConflictFilter: function (user_id){
		// DFCT0011556 - needed to return undefined instead of an empty string for the fitler to keep it from adding the banner
		var conflictingTaskQuery;
		var oooCount = 0;
		// DFCT0011562 - fitler out active
		// DFCT0011561 - DFCT0011559 ^ did not work with NQ

		var taskFitler = "active=true";
		// DFCT0011555 - filter out Draft
		taskFitler += "^state!=-6";
		// first get the current and future Out of Office dates for this user
		var userFilter = "^assigned_to=" + user_id + "^ORu_reviewer=" + user_id + "^ORu_task_requester=" + user_id;
		var emptySuspenseDateQuery = "^suspense_dateISEMPTY"; 
		var suspenseDateQuery = "";
		var earliestStart="";
		var grUserOOO = new GlideRecord(Out_of_Office.CONST_TABLE_NAME_OUT_OF_OFFICE);
		grUserOOO.addQuery("u_user", user_id);
		grUserOOO.addQuery("u_end_date", ">=", gs.daysAgoStart(0));
		// if the earliest start date is before the suspense date, then the user has a conflicting ooo
		grUserOOO.orderBy("u_start_date");
		grUserOOO.query();
		if(grUserOOO.next()){
			oooCount++;
			earliestStart = grUserOOO.u_start_date;
		}
		if(oooCount > 0 ){
			// DFCT0011562 - fitler out active and DFCT0011555 - filter out Draft into both parts of query

			// create query for tasks with no suspense date.  
			// If the user has any current or future out of office dates, 
			// this is all task where the user is the Owner, Reviewer or Assigned Member
			conflictingTaskQuery = taskFitler + emptySuspenseDateQuery + userFilter + "^NQ";
			// create query for tasks with suspense date
			// This will be all of the tasks where the User is the Owner, Reviewer or Assigned Member 
			// and the out of office dates overlap with the suspense date of the task
			conflictingTaskQuery += taskFitler + "^suspense_dateISNOTEMPTY^suspense_date>=" + earliestStart + userFilter;

		}
		return conflictingTaskQuery;
	},


    type: 'Out_of_Office'
};
